extra.modelCss:
/* Landing page (CSS base do projeto) */

:root {
  --bg: #0b0f19;
  --panel: #111827;
  --text: #e5e7eb;
  --muted: #9ca3af;
  --accent: #60a5fa;
  --border: rgba(255, 255, 255, 0.10);
  --radius: 14px;
  --shadow-1: 0 6px 16px rgba(0, 0, 0, 0.12);
  --shadow-2: 0 16px 40px rgba(0, 0, 0, 0.16);
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
  line-height: 1.6;
}

.container {
  max-width: 1100px;
  margin: 0 auto;
  padding: 16px;
}

@media (min-width: 768px) {
  .container { padding: 24px; }
}

@media (min-width: 1024px) {
  .container { padding: 32px; }
}

.section {
  padding: 24px 0;
}

@media (min-width: 768px) {
  .section { padding: 40px 0; }
}

/* Navbar */
.navbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 12px 16px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  background: rgba(255, 255, 255, 0.02);
}

.brand { font-weight: 800; }

.nav-links {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.nav-link {
  text-decoration: none;
  color: var(--text);
  padding: 10px 12px;
  border-radius: 12px;
}

.nav-link:hover,
.nav-link:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}

/* Hero */
.hero {
  display: grid;
  gap: 20px;
  align-items: center;
}

.hero__content {
  max-width: 65ch;
}

.hero__title {
  font-size: 2rem;
  line-height: 1.2;
  margin: 0;
}

@media (min-width: 1024px) {
  .hero {
    grid-template-columns: 1.2fr 1fr;
  }
  .hero__title {
    font-size: 2.6rem;
  }
}

.hero__subtitle {
  color: var(--muted);
}

/* Buttons */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: 12px;
  border: 1px solid transparent;
  font-weight: 700;
  cursor: pointer;
  transition: transform 150ms ease, opacity 150ms ease;
}

.btn:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}

.btn:hover {
  transform: translateY(-1px);
  opacity: 0.95;
}

.btn.primary {
  background: var(--accent);
  color: #0b0f19;
}

.btn.ghost {
  background: transparent;
  color: var(--text);
  border-color: var(--border);
}

/* Features grid */
.grid-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 16px;
}

.card {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-1);
}

.card-inner {
  padding: 16px;
  display: grid;
  gap: 10px;
}

/* CTA */
.cta {
  background: rgba(96, 165, 250, 0.10);
  border: 1px solid rgba(96, 165, 250, 0.25);
  border-radius: var(--radius);
  padding: 16px;
  display: grid;
  gap: 12px;
}

@media (min-width: 768px) {
  .cta {
    padding: 24px;
  }
}

.footer {
  padding: 24px 0;
  color: var(--muted);
}

@media (prefers-reduced-motion: reduce) {
  * {
    transition: none !important;
    animation: none !important;
  }
}
